import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

@RestController
public class MathController {
    @GetMapping("/factorial")
    public long factorial(@RequestParam int number) {
        if (number < 0) {
            throw new IllegalArgumentException("Number must be non-negative");
        }
        long result = 1;
        for (int i = 2; i <= number; i++) {
            result *= i;
        }
        return result;
    }
}

import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

@RestController
public class MathController {
    @GetMapping("/prime")
    public boolean isPrime(@RequestParam int number) {
        if (number < 2) {
            return false;
        }
        for (int i = 2; i <= Math.sqrt(number); i++) {
            if (number % i == 0) {
                return false;
            }
        }
        return true;
    }
}

import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;
import java.util.ArrayList;
import java.util.List;

@RestController
public class MathController {
    @GetMapping("/fibonacci")
    public java.util.List<Integer> fibonacci(@RequestParam int count) {
        java.util.List<Integer> sequence = new java.util.ArrayList<>();
        int first = 0;
        int second = 1;
        for (int i = 0; i < count; i++) {
            sequence.add(first);
            int next = first + second;
            first = second;
            second = next;
        }
        return sequence;
    }
}

