import org.springframework.web.bind.annotation.RestController;

record RefreshRequest(String refreshToken) {}
record TokenResponse(String accessToken, String refreshToken) {}

@RestController
@RequestMapping("/api/auth")
public class RefreshTokenController {
    private final RefreshTokenService refreshTokenService;
    private final JwtService jwtService;

    public RefreshTokenController(RefreshTokenService refreshTokenService, JwtService jwtService) {
        this.refreshTokenService = refreshTokenService;
        this.jwtService = jwtService;
    }

    @PostMapping("/refresh")
    public ResponseEntity<TokenResponse> refresh(@RequestBody RefreshRequest request) {
        String username = refreshTokenService.validateAndGetUsername(request.refreshToken());
        String accessToken = jwtService.generateToken(username);
        return ResponseEntity.ok(new TokenResponse(accessToken, request.refreshToken()));
    }
}

