    }
}

@Configuration
class WebConfig implements WebMvcConfigurer {
    private final RequestIdInterceptor interceptor;

    WebConfig(RequestIdInterceptor interceptor) {
        this.interceptor = interceptor;
    }

    public void addInterceptors(InterceptorRegistry registry) {
        registry.addInterceptor(interceptor).addPathPatterns("/api/**");
    }
}

import org.springframework.stereotype.Service;
import org.springframework.web.multipart.MultipartFile;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.UUID;

@Service
public class FileStorageService {
    private final Path uploadDir = Path.of("uploads");

    public String store(MultipartFile file) throws IOException {
        Files.createDirectories(uploadDir);
        String filename = UUID.randomUUID() + "-" + file.getOriginalFilename();
        Path destination = uploadDir.resolve(filename);
        file.transferTo(destination);
        return filename;
    }
}

import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.multipart.MultipartFile;
import java.io.IOException;
import java.util.Arrays;
import java.util.List;

@RestController
public class MultiFileUploadController {
    private final FileStorageService fileStorageService;

    public MultiFileUploadController(FileStorageService fileStorageService) {
        this.fileStorageService = fileStorageService;
    }

    @PostMapping("/files/upload-many")
    public ResponseEntity<List<String>> uploadMany(@RequestParam("files") MultipartFile[] files) {
        List<String> names = Arrays.stream(files)
                .map(file -> fileStorageService.store(file))
                .toList();
        return ResponseEntity.ok(names);
    }
}

import org.springframework.core.io.Resource;
import org.springframework.core.io.UrlResource;
import org.springframework.http.HttpHeaders;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RestController;
import java.net.MalformedURLException;
import java.nio.file.Path;

@RestController
public class ImageDownloadController {
    private final Path uploadDir = Path.of("uploads");

    @GetMapping("/api/images/{fileName}")
    public ResponseEntity<Resource> download(@PathVariable String fileName) throws MalformedURLException {
        Resource resource = new UrlResource(uploadDir.resolve(fileName).normalize().toUri());
        return ResponseEntity.ok()
                .header(HttpHeaders.CONTENT_DISPOSITION, "attachment; filename=\"" + resource.getFilename() + "\"")
                .body(resource);
    }
}

import jakarta.mail.MessagingException;
import jakarta.mail.internet.MimeMessage;
import org.springframework.mail.javamail.JavaMailSender;
import org.springframework.mail.javamail.MimeMessageHelper;
import org.springframework.stereotype.Service;

@Service
public class HtmlEmailService {
    private final JavaMailSender mailSender;

    public HtmlEmailService(JavaMailSender mailSender) {
        this.mailSender = mailSender;
    }

    public void sendHtmlEmail(String to, String subject, String html) throws MessagingException {
        MimeMessage message = mailSender.createMimeMessage();
        MimeMessageHelper helper = new MimeMessageHelper(message, true, "UTF-8");
        helper.setTo(to);
        helper.setSubject(subject);
        helper.setText(html, true);
        mailSender.send(message);
    }
}

